head.script:
//==================================================================================================================
// id       : op_202_03_02b 
// 이름     : 역별작업일자별예정물량조회
// 경로     : 물류/작업계획/철송/
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-30
// 사용계정 : 내부
// 비고     : 
// 레포트   :
//              op_202_03_02r (출발역발행 버튼클릭, 도착역발행 버튼클릭)
//              op_202_02_03r (오더SHEET 버튼클릭)
// 업로드   :
// 다운로드 : 
// 호출     :
//            
//==================================================================================================================
scwin.onloadRetrieve;
scwin.v_loadRegYn;

scwin.onpageload = async function() {
    scwin.onloadRetrieve  = true;   //조회 여부
    scwin.v_loadRegYn     = 0;

    const codeOptions = [ 
        {
            method: "getLuxeComboData", 
            param1: "WorkImplementEBC", 
            param2: "retriveLobran2CodeList",
            //param3: ["CMP"],
            compID: "acb_alloccarBran" 
        }
    ];
    $c.data.setGauceUtil(codeOptions, scwin.getLuxeComboDataCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.getLuxeComboDataCallBack = function(){
    $p.setTimeout(function() {
        acb_alloccarBran.addItem("", "전체", 0);
        acb_alloccarBran.setSelectedIndex(0);

        ica_qryDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
        ica_qryDtTo.setValue($c.date.getServerDateTime("yyyyMMdd"));
        acb_dptArvCls.setSelectedIndex(0);

        scwin.onloadRetrieve = false;

        // ica_qryDt.setValue("20240101")
        // ica_qryDtTo.setValue("20240131")
    }, {"delay":150});
};

//-------------------------------------------------------------------------
// clear 버튼 클릭시(조회)
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition);
    ica_qryDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
    ica_qryDtTo.setValue($c.date.getServerDateTime("yyyyMMdd"));
};

//-------------------------------------------------------------------------
// clear 버튼 클릭시(일괄적용)
//-------------------------------------------------------------------------
scwin.f_FieldClear2 = function () {
    $c.gus.cfInitObjects(tb_batchCondition);
};

//-------------------------------------------------------------------------
// 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel1 = function () {
    //sheet명, 저장파일명,     저장 다이얼로그
    // cfGridToExcel(gr_retrieve, "오더별철송구간목록", "오더별철송구간목록.xls", 4+8+16);
    const infoArr = [];
    const options = {
        fileName : "오더별철송구간목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "오더별철송구간목록",
        useSubTotal :"true", 
        useSubTotalData  : "true",
        type : "1"
    };
    $c.data.downloadGridViewExcel(gr_retrieve, options, infoArr);
};

//-------------------------------------------------------------------------
// 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel2 = function () {
    //sheet명, 저장파일명,     저장 다이얼로그
    // cfGridToExcel(gr_retrieveDtl, "오더별컨테이너목록", "오더별컨테이너목록.xls", 2+4+8+16);
    const infoArr = [];
    const options = {
        fileName : "오더별컨테이너목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "오더별컨테이너목록",
        useSubTotal :"true", 
        useSubTotalData  : "true",
        type : "1"
    };
    // var jsonData = {
    //     "fileName":"오더별컨테이너목록.xlsx",
    //     "type":"2+4+8+16"
    // };
    // udc_topBottonArea.setDownOpts(jsonData)
    gr_retrieveDtl.setColumnVisible("odrNo", true);
    $c.data.downloadGridViewExcel(gr_retrieveDtl, options, infoArr);
    gr_retrieveDtl.setColumnVisible("odrNo", false);
};

//-------------------------------------------------------------------------
// 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel3 = async function () {
    //sheet명, 저장파일명,     저장 다이얼로그
    // 240429 - 오더별컨테이너 전체 엑셀다운 미체크 후 데이터 조회 -> 체크 후 엑셀 DN시 select 결과가 없어 다운이 안되는 것을 방지
    const infoArr = [];
    const options = {
        fileName : "오더별컨테이너 전체목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "오더별컨테이너 전체목록",
        useSubTotal :"true", 
        useSubTotalData  : "true",
        type : "1"
    };
    // var jsonData = {
    //     "fileName":"오더별컨테이너 전체목록.xlsx",
    //     "type":"4+8+16"
    // };
    // udc_topBottonArea.setDownOpts(jsonData);

    if (!ds_retrieveDtlAll.getRowCount() > 0){
        var rs = await $c.sbm.execute(sbm_retrieve1);
        if(rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            $c.data.downloadGridViewExcel(gr_retrieveDtlAll, options, infoArr);
        }
    }else{
        // cfGridToExcel(gr_retrieveDtlAll, "오더별컨테이너 전체목록", "오더별컨테이너 전체목록.xls", 4+8+16);
        $c.data.downloadGridViewExcel(gr_retrieveDtlAll, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// 체크박스 체크 여부에 따라서 저장할 그리드 데이터 분기
//-------------------------------------------------------------------------
scwin.f_swapingExcel = function (){
    if(cbx_allOdrYn.getValue() == "1"){
        scwin.f_toExcel3();
    }else{
        scwin.f_toExcel2();
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
        //출발역
        udc_dptStn.setSelectId('retrieveTrainWorkPlace');
        udc_dptStn.cfCommonPopUp(scwin.udc_dptStn_callBackFunc   // XML상의 SELECT ID
                                ,pCode                    // 화면에서의 ??? Code Element의    Value
                                ,pName                    // 화면에서의 ??? Name Element의    Value
                                ,pClose                   // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                ,null                     // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,"출발역코드,출발역명"    // Title순서
                                ,null                     // 보여주는 각 컬럼들의 폭
                                ,null                     // 컬럼중에서 숨기는    컬럼 지정
                                ,null                     // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                     // POP-UP뛰을때 원도우의    사용자 정의 폭
                                ,null                     // POP-UP뛰을때 우도우의    사용자 정의 높이
                                ,null                     // 윈도우 위치 Y좌표
                                ,null                     // 윈도우 위치 X좌표
                                ,null                     // 중복체크여부 ("F")
                                ,pAllSearch               // 전체검색허용여부 ("F")
                                ,"출발역조회,출발역코드,출발역명" // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
        break;
    case 2:
        //도착역
        udc_arvStn.setSelectId('retrieveTrainWorkPlace');
        udc_arvStn.cfCommonPopUp(scwin.udc_arvStn_callBackFunc    // XML상의 SELECT ID
                                ,pCode                      // 화면에서의 ??? Code Element의    Value
                                ,pName                      // 화면에서의 ??? Name Element의    Value
                                ,pClose                     // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                ,null                       // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,"도착역코드,도착역명"      // Title순서
                                ,null                       // 보여주는 각 컬럼들의 폭
                                ,null                       // 컬럼중에서 숨기는    컬럼 지정
                                ,null                       // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                       // POP-UP뛰을때 원도우의    사용자 정의 폭
                                ,null                       // POP-UP뛰을때 우도우의    사용자 정의 높이
                                ,null                       // 윈도우 위치 Y좌표
                                ,null                       // 윈도우 위치 X좌표
                                ,null                       // 중복체크여부 ("F")
                                ,pAllSearch                 // 전체검색허용여부 ("F")
                                ,"도착역조회,도착역코드,도착역명"   // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
        break;
    case 3:
        //현위치
        udc_currPos.setSelectId('retrieveWrkPlInfo');
        udc_currPos.cfCommonPopUp(scwin.udc_currPos_callBackFunc    // XML상의 SELECT ID
                                 ,pCode                      // 화면에서의 ??? Code Element의    Value
                                 ,pName                      // 화면에서의 ??? Name Element의    Value
                                 ,pClose                     // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                 ,null                       // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                 ,"현위치코드,현위치명"      // Title순서
                                 ,null                       // 보여주는 각 컬럼들의 폭
                                 ,null                       // 컬럼중에서 숨기는    컬럼 지정
                                 ,"CURPOS"                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                 ,null                       // POP-UP뛰을때 원도우의    사용자 정의 폭
                                 ,null                       // POP-UP뛰을때 우도우의    사용자 정의 높이
                                 ,null                       // 윈도우 위치 Y좌표
                                 ,null                       // 윈도우 위치 X좌표
                                 ,null                       // 중복체크여부 ("F")
                                 ,pAllSearch                 // 전체검색허용여부 ("F")
                                 ,"현위치조회,현위치코드,현위치명"   // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
        break;
    case 4:
        //출발역(일괄적용)
        udc_batchDptStn.setSelectId('retrieveTrainWorkPlace');
        udc_batchDptStn.cfCommonPopUp(scwin.udc_batchDptStn_callBackFunc   // XML상의 SELECT ID
                                     ,pCode                    // 화면에서의 ??? Code Element의    Value
                                     ,pName                    // 화면에서의 ??? Name Element의    Value
                                     ,pClose                   // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                     ,null                     // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                     ,"출발역코드,출발역명"    // Title순서
                                     ,null                     // 보여주는 각 컬럼들의 폭
                                     ,null                     // 컬럼중에서 숨기는    컬럼 지정
                                     ,null                     // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                     ,null                     // POP-UP뛰을때 원도우의    사용자 정의 폭
                                     ,null                     // POP-UP뛰을때 우도우의    사용자 정의 높이
                                     ,null                     // 윈도우 위치 Y좌표
                                     ,null                     // 윈도우 위치 X좌표
                                     ,null                     // 중복체크여부 ("F")
                                     ,pAllSearch               // 전체검색허용여부 ("F")
                                     ,"출발역조회,출발역코드,출발역명" // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
        break;
    case 5:
        //도착역(일괄적용)
        udc_batchArvStn.setSelectId('retrieveTrainWorkPlace');
        udc_batchArvStn.cfCommonPopUp(scwin.udc_batchArvStn_callBackFunc    // XML상의 SELECT ID
                                     ,pCode                      // 화면에서의 ??? Code Element의    Value
                                     ,pName                      // 화면에서의 ??? Name Element의    Value
                                     ,pClose                     // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                                     ,null                       // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                     ,"도착역코드,도착역명"      // Title순서
                                     ,null                       // 보여주는 각 컬럼들의 폭
                                     ,null                       // 컬럼중에서 숨기는    컬럼 지정
                                     ,null                       // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                     ,null                       // POP-UP뛰을때 원도우의    사용자 정의 폭
                                     ,null                       // POP-UP뛰을때 우도우의    사용자 정의 높이
                                     ,null                       // 윈도우 위치 Y좌표
                                     ,null                       // 윈도우 위치 X좌표
                                     ,null                       // 중복체크여부 ("F")
                                     ,pAllSearch                 // 전체검색허용여부 ("F")
                                     ,"도착역조회,도착역코드,도착역명"   // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
        break;
    }//end switch
};

//-------------------------------------------------------------------------
// 그리드에서 입력된 코드/명칭 정보로  조회 (Grid PopUp)
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = function (disGubun, row, pClose) {
    // 선언부
    var pCode = "";
    var pName = "";
    switch (disGubun) {
        case 1:
            //출발역
            pName = ds_retrieveDtl.getCellData(row, "dptWrkPlNm");  //출발역명
            udc_grdTextImage.setSelectId('retrieveTrainWorkPlace');
            udc_grdTextImage.cfCommonPopUp(
                function(ref){
                    $c.gus.cfSetGridReturnValue(ref, ds_retrieveDtl, row, "dptWrkPlCd", "dptWrkPlNm");
                }   
                ,pCode                    // 화면에서의 ??? Code Element의    Value
                ,pName                    // 화면에서의 ??? Name Element의    Value
                ,pClose                   // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                ,null                     // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                ,"출발역명코드,출발역명"  // Title순서
                ,null                     // 보여주는 각 컬럼들의 폭
                ,null                     // 컬럼중에서 숨기는    컬럼 지정
                ,null                     // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                ,null                     // POP-UP뛰을때 원도우의    사용자 정의 폭
                ,null                     // POP-UP뛰을때 우도우의    사용자 정의 높이
                ,null                     // 윈도우 위치 Y좌표
                ,null                     // 윈도우 위치 X좌표
                ,null                     // 중복체크여부 ("F")
                ,'F'                      // 전체검색허용여부 ("F")
                ,"출발역조회,출발역명코드,출발역명" // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;
        case 2:
            //도착역
            pName = ds_retrieveDtl.getCellData(row, "arvWrkPlNm");  //도착역명
            udc_grdTextImage.setSelectId('retrieveTrainWorkPlace');
            udc_grdTextImage.cfCommonPopUp(
                function(ref){
                    $c.gus.cfSetGridReturnValue(ref, ds_retrieveDtl, row, "arvWrkPlCd", "arvWrkPlNm");
                }
                ,pCode                      // 화면에서의 ??? Code Element의    Value
                ,pName                      // 화면에서의 ??? Name Element의    Value
                ,pClose                     // 결과가 1건 일때  원도우를    AutoClose 여부  (T:Close,F:Opened)
                ,null                       // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                ,"도착역명코드,도착역명"    // Title순서
                ,null                       // 보여주는 각 컬럼들의 폭
                ,null                       // 컬럼중에서 숨기는    컬럼 지정
                ,null                       // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                ,null                       // POP-UP뛰을때 원도우의    사용자 정의 폭
                ,null                       // POP-UP뛰을때 우도우의    사용자 정의 높이
                ,null                       // 윈도우 위치 Y좌표
                ,null                       // 윈도우 위치 X좌표
                ,null                       // 중복체크여부 ("F")
                ,'F'                      // 전체검색허용여부 ("F")
                ,"도착역명조회,도착역명코드,도착역명"   // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
