scwin.f_Retrieve = async function () {
    // 필수항목 체크
    if(!await $c.gus.cfValidate([tb_searchCondition])){
        return;
    }
    if (!await $c.gus.cfIsAfterDate(ica_qryDt.getValue(), ica_qryDtTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_qryDt.focus();
        return;
    }
    // 적재내역등록여부
    if(cbx_loadRegYn.getValue() == 1) {
        cbx_loadRegYn.setValue("1");
        scwin.v_loadRegYn = 1;
    } else {
        cbx_loadRegYn.setValue("0");
        scwin.v_loadRegYn = 0;
    }  
    ds_search.set("loadRegYn", cbx_loadRegYn.getValue());
    //출발도착구분이 출발인 경우
    if(acb_dptArvCls.getValue() == 'D'){
        // ds_retrieve.SortExpr   = "+lobranNm+dptWrkPlNm+arvWrkPlNm+odrNo";
        // ds_retrieve.SubSumExpr = "2:lobranNm,1:dptWrkPlNm:arvWrkPlNm";
        // ds_retrieve.Sort();
        // var options = {
        //     sortIndex : "lobranNm dptWrkPlNm arvWrkPlNm odrNo",
        //     sortOrder : "1 1 1 1"
        // };
        // ds_retrieve.multisort(options);

    } else if(acb_dptArvCls.getValue() == 'A' ){
        // ds_retrieve.SortExpr   = "+arvWrkPlNm+dptWrkPlNm+odrNo";
        // ds_retrieve.SubSumExpr = "1:arvWrkPlNm";
        // ds_retrieve.Sort();
        // var options = {
        //     sortIndex : "arvWrkPlNm dptWrkPlNm odrNo",
        //     sortOrder : "1 1 1"
        // };
        // ds_retrieve.multisort(options);
    }
    ds_retrieve.removeAll();
    ds_retrieveDtl.removeAll();
    scwin.onloadRetrieve = true;

    $c.sbm.execute(sbm_retrieve);

    scwin.onloadRetrieve = false;
}

