scwin.f_RetrieveDtl = async function () {
    var row = ds_retrieve.getRowPosition();
    var p_odrNo       = ds_retrieve.getCellData(row, "odrNo");          //오더번호
    var p_dptWrkPlCd  = ds_retrieve.getCellData(row, "dptWrkPlCd");     //출발역코드
    var p_arvWrkPlCd  = ds_retrieve.getCellData(row, "arvWrkPlCd");     //도착역코드
    var p_dptArvCls   = acb_dptArvCls.getValue();                       //출발도착구분(D:출발,A:도착)
    var p_qryDt       = ica_qryDt.getValue();                           //예정일자
    var p_qryDtTo     = ica_qryDtTo.getValue();                         //예정일자

    if(await $c.gus.cfIsNull( p_odrNo ) ) return;

    // 적재내역등록여부(retrieve조회 후 체크박스를 해제 또는 설정 하는 경우대비
    if(cbx_loadRegYn.getValue() == 1) {
        scwin.v_loadRegYn = 1;
    } else {
        scwin.v_loadRegYn = 0;
    }     

    // var param = "";
    // param = "/ds.op.wrkplan.volconfirm.RetrieveOrderEachRailroadDistanceCMD.do?"
    //     + "odrNo=" + p_odrNo          + "&dptWrkPlCd=" + p_dptWrkPlCd + "&arvWrkPlCd=" + p_arvWrkPlCd
    //     + "&dptArvCls=" + p_dptArvCls + "&qryDt=" + p_qryDt + "&qryDtTo=" + p_qryDtTo + "&loadRegYn=" + scwin.v_loadRegYn ;
    ds_searchRetrieveDtl.set("odrNo", p_odrNo);
    ds_searchRetrieveDtl.set("dptWrkPlCd", p_dptWrkPlCd);
    ds_searchRetrieveDtl.set("arvWrkPlCd", p_arvWrkPlCd);
    ds_searchRetrieveDtl.set("dptArvCls", p_dptArvCls);
    ds_searchRetrieveDtl.set("qryDt", p_qryDt);
    ds_searchRetrieveDtl.set("qryDtTo", p_qryDtTo);
    ds_searchRetrieveDtl.set("loadRegYn", scwin.v_loadRegYn);
    ds_retrieveDtl.removeAll();
    $c.sbm.execute(sbm_retrieveDtl);

};

