//-------------------------------------------------------------------------
// 일괄적용
//-------------------------------------------------------------------------
scwin.f_BatchApply = async function () {
    // 필수항목 체크
    if(!await $c.gus.cfValidate([tb_batchCondition],null,true)){
        return;
    }
    var p_batchDptStnCd = ed_batchDptStnCd.getValue();      //출발역코드
    var p_batchDptStnNm = ed_batchDptStnNm.getValue();    //출발역
    var p_batchArvStnCd = ed_batchArvStnCd.getValue();      //도착역코드
    var p_batchArvStnNm = ed_batchArvStnNm.getValue();    //도착역
    var p_batchWrkStDt  = ica_batchWrkStDt.getValue();       //출발예정일자
    var p_batchWrkStHh  = ed_batchWrkStHh.getValue();       //출발예정시간
    var p_batchWrkEndDt = ica_batchWrkEndDt.getValue();      //도착예정일자
    var p_batchWrkEndHh = ed_batchWrkEndHh.getValue();      //도착예정시간

    var p_batchWrkStDtm   = p_batchWrkStDt + p_batchWrkStHh;
    var p_batchWrkEndDtm  = p_batchWrkEndDt + p_batchWrkEndHh;

    if(!await $c.gus.cfIsNull( p_batchDptStnCd ) && !await $c.gus.cfIsNull( p_batchArvStnCd ) && p_batchDptStnCd == p_batchArvStnCd) {
        await $c.gus.cfAlertMsg("출발역과 도착역이 같으면 안 됩니다.");
        return;
    }

    if(!await $c.gus.cfIsNull(p_batchWrkStDt) && !await $c.gus.cfIsNull(p_batchWrkEndDt)){
        if (!await $c.gus.cfIsAfterDate(p_batchWrkStDt, p_batchWrkEndDt)) {
            await $c.gus.cfAlertMsg( "출발예정일자가 도착예정일자 이전이어야 합니다." );
            return;
        }
        if(!await $c.gus.cfIsNull( p_batchWrkStHh ) && !await $c.gus.cfIsNull( p_batchWrkEndHh )){
            if(parseInt(p_batchWrkStDtm) >= parseInt(p_batchWrkEndDtm)) {
                await $c.gus.cfAlertMsg("출발예정일시가 도착예정일시 이전이어야 합니다.");
                return;
            }
        }
    }//end if
    for( var i = 0; i < ds_retrieveDtl.getRowCount(); i++ ) {
        if(!await $c.gus.cfIsNull( p_batchDptStnCd ) && !await $c.gus.cfIsNull( p_batchDptStnNm ) ) {
            ds_retrieveDtl.setCellData( i, "dptWrkPlCd", p_batchDptStnCd );    //출발역코드
            ds_retrieveDtl.setCellData( i, "dptWrkPlNm", p_batchDptStnNm );    //출발역
        }
        if(!await $c.gus.cfIsNull( p_batchArvStnCd ) && !await $c.gus.cfIsNull( p_batchArvStnNm ) ) {
            ds_retrieveDtl.setCellData( i, "arvWrkPlCd", p_batchArvStnCd );    //도착역코드
            ds_retrieveDtl.setCellData( i, "arvWrkPlNm", p_batchArvStnNm );    //도착역
        }
        if(!await $c.gus.cfIsNull( p_batchWrkStDt ) ) {
            ds_retrieveDtl.setCellData( i, "wrkStDt", p_batchWrkStDt );     //출발예정일자
        }
        if(!await $c.gus.cfIsNull( p_batchWrkStHh ) ) {
            ds_retrieveDtl.setCellData( i, "wrkStHh", p_batchWrkStHh );     //출발예정시간
        }
        if(!await $c.gus.cfIsNull( p_batchWrkEndDt )  ) {
            ds_retrieveDtl.setCellData( i, "wrkEndDt", p_batchWrkEndDt );    //도착예정일자
        }
        if(!await $c.gus.cfIsNull( p_batchWrkEndHh ) ) {
            ds_retrieveDtl.setCellData( i, "wrkEndHh", p_batchWrkEndHh );    //도착예정시간
        }
    }//end for
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    var modifiedCnt = ds_retrieveDtl.getModifiedIndex().length;
    //데이터셋의 변경여부 체크
    if(!modifiedCnt > 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["오더별 컨테이너 목록"]); //@은(는) 변경된 사항이 없습니다.
        return;
    }
    //가우스의 Grid에 대해 유효성 검사
    // if(!await $c.gus.cfValidateGrid( [gr_retrieveDtl] ) ) return;
    if(!await $c.gus.cfValidate([gr_retrieveDtl],null,true) ) return;

    for( var i = 0; i < ds_retrieveDtl.getRowCount(); i++ ) {
        //수정시
        if(ds_retrieveDtl.getRowStatus(i) == "U" ) {

            var p_wrkStDt         = ds_retrieveDtl.getCellData( i, "wrkStDt" );         //출발예정일자
            var p_wrkStHh         = ds_retrieveDtl.getCellData( i, "wrkStHh" );         //출발예정시간
            var p_wrkEndDt        = ds_retrieveDtl.getCellData( i, "wrkEndDt" );        //도착예정일자
            var p_wrkEndHh        = ds_retrieveDtl.getCellData( i, "wrkEndHh" );        //도착예정시간
            var p_basisWrkStDtm   = ds_retrieveDtl.getCellData( i, "basisWrkStDtm" );   //근거작업시작일시
            var p_basisWrkEndDtm  = ds_retrieveDtl.getCellData( i, "basisWrkEndDtm" );  //근거작업종료일시

            var p_wrkStDtm        = p_wrkStDt + p_wrkStHh;
            var p_wrkEndDtm       = p_wrkEndDt + p_wrkEndHh;

            var p_formatBasisWrkStDtm = p_basisWrkStDtm.substring(0,4) + "/" + p_basisWrkStDtm.substring(4,6) + "/" + p_basisWrkStDtm.substring(6,8) + " " + p_basisWrkStDtm.substring(8,10) + ":" + p_basisWrkStDtm.substring(10,12);
            var p_formatBasisWrkEndDtm = p_basisWrkEndDtm.substring(0,4) + "/" + p_basisWrkEndDtm.substring(4,6) + "/" + p_basisWrkEndDtm.substring(6,8) + " " + p_basisWrkEndDtm.substring(8,10) + ":" + p_basisWrkEndDtm.substring(10,12);

            if(ds_retrieveDtl.getCellData( i, "dptWrkPlCd" ) == ds_retrieveDtl.getCellData( i, "arvWrkPlCd" ) ) {
                await $c.gus.cfAlertMsg( (i+1) + "번째 출발역과 도착역이 같으면 안 됩니다." );
                return;
            }

            //from~to의 일자 유효성체크
            if(parseInt( p_wrkStDtm ) >= parseInt( p_wrkEndDtm ) ) {
                await $c.gus.cfAlertMsg( (i+1) + "번째 출발예정일시가 도착예정일시 이전이어야 합니다." );
                return;
            }
            if(parseInt( p_wrkStDtm ) < parseInt( p_basisWrkStDtm ) ) {
                await $c.gus.cfAlertMsg( (i+1) + "번째 출발예정일시는 작업시작일시("+ p_formatBasisWrkStDtm +")와 작업종료일시("+ p_formatBasisWrkEndDtm +") 사이이어야 합니다." );
                return;
            }
        }
    }//end for
    if(await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?
        $c.sbm.execute(sbm_save);
    }
};

