scwin.sbm_retrieve_submit = function (e) {
    ds_search.set("alloccarBran", acb_alloccarBran.getValue());  // 배차점소
    ds_search.set("dptArvCls", acb_dptArvCls.getValue());        // 도착
    ds_search.set("qryDt", ica_qryDt.getValue());                // 예정일자From
    ds_search.set("qryDtTo", ica_qryDtTo.getValue());            // 예정일자To
	ds_search.set("loadRegYn", cbx_loadRegYn.getValue());        // 적재내역등록여부
    ds_search.set("dptStnCd", ed_dptStnCd.getValue());          // 출발역
    ds_search.set("arvStnCd", ed_arvStnCd.getValue());          // 도착역
    ds_search.set("currPosCd", ed_currPosCd.getValue());        // 현위치
};

scwin.sbm_retrieve_submitdone = async function (e) {
    var rowCnt = ds_retrieve.getRowCount();
    if (cbx_allOdrYn.getValue() == 1) $c.sbm.execute(sbm_retrieve1);
    if (rowCnt == 0 ){
        await $c.gus.cfAlertMsg( MSG_CM_WRN_002 );
    }
    // 총 조회건수 표시
    txt_totalRows1.setValue(rowCnt);

    //출발인 경우 D1
    if(acb_dptArvCls.getValue() == 'D' ){
        scwin.drawRetrieveGrid("D1");

    //도착인 경우 A1
    } else if(acb_dptArvCls.getValue() == 'A' ){
        scwin.drawRetrieveGrid("A1");

    }
    scwin.f_RetrieveDtl();  //상세조회
};

