scwin.gr_retrieve_onaftercolumnmove = function (info) {
    // OnColIndexChanged(srcIndex, destIndex)
    $p.setTimeout(function() {
        //배차점소인 경우
        if("lobranNm" == info.startColumnID) {
            // ds_retrieve.SortExpr ="+lobranNm";
            // ds_retrieve.SubsumExpr = "2:lobranNm,1:dptWrkPlNm:arvWrkPlNm" ;
            // ds_retrieve.Sort();
            scwin.drawRetrieveGrid("A2");

        //출발역인 경우
        } else if("dptWrkPlNm" == info.startColumnID) {

            // ds_retrieve.SortExpr ="+dptWrkPlNm+arvWrkPlNm";
            // ds_retrieve.SubsumExpr = "1:dptWrkPlNm" ;
            // ds_retrieve.Sort();
            scwin.drawRetrieveGrid("A3");

        //도착역인 경우
        } else if("arvWrkPlNm" == info.startColumnID) {

            // ds_retrieve.SortExpr ="+arvWrkPlNm+dptWrkPlNm";
            // ds_retrieve.SubsumExpr = "1:arvWrkPlNm" ;
            // ds_retrieve.Sort();
            scwin.drawRetrieveGrid("A1");
        }
        scwin.f_RetrieveDtl();  //상세조회
    }, {"delay":100});
};

scwin.gr_retrieve_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    if(scwin.onloadRetrieve == false ) {
        scwin.f_RetrieveDtl();  //상세조회
    }
};

scwin.gr_retrieveDtl_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    //계약한 경우(존재여부=1)에는 수정불가
    if(ds_retrieveDtl.getCellData( rowIndex, "existFlag" ) == "1" ) {
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'dptWrkPlNm', true);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'arvWrkPlNm', true);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkStDt', true);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkStHh', true);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkEndDt', true);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkEndHh', true);
    } else {
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'dptWrkPlNm', false);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'arvWrkPlNm', false);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkStDt', false);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkStHh', false);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkEndDt', false);
        gr_retrieveDtl.setCellReadOnly(rowIndex, 'wrkEndHh', false);
    }

    // switch (Colid) {
    //     case "wrkStDt":
    //     gr_retrieveDtl.UrlImages = CALENDAR_BTN;
    //     break;
    //     case "wrkEndDt":
    //     gr_retrieveDtl.UrlImages = CALENDAR_BTN;
    //     break;
    //     default:
    //     gr_retrieveDtl.UrlImages = SEARCH_BTN;
    //     break;
    // }
};

