scwin.drawRetrieveGrid = function(type){
    var gr_retrieve_target = '<w2:gridView xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" '
    gr_retrieve_target += '    autoFit="none" checkReadOnlyOnPasteEnable="" class="wq_gvw" dataList="data:ds_retrieve" rowStatusVisible="true" drawType="virtual"' // virtual, native
    if (acb_dptArvCls.getValue() == "D"){
        gr_retrieve_target += ' columnMove="true"'
    } else {
        gr_retrieve_target += ' columnMove="false"'
    }
    gr_retrieve_target += '    focusMode="row" id="gr_retrieve" scrollByColumn="false" scrollByColumnAdaptive="false" style="height: 282px;" visibleRowNum="8" sortable="false"'
    gr_retrieve_target += '    visibleRowNumFix="true" ev:onaftercolumnmove="scwin.gr_retrieve_onaftercolumnmove" ev:oncellindexchange="scwin.gr_retrieve_oncellindexchange">'
    gr_retrieve_target += '    <w2:caption id="caption1" style="" value="this is a grid caption."></w2:caption>'
    gr_retrieve_target += '    <w2:header id="header2" style="">'
    gr_retrieve_target += '        <w2:row id="row3" style="">'
    if (type == "D1" || type == "A2"){
        // gr_retrieve_target += '<c> id="lobranNm"            name="배차점소"             width=70 align=center value={decode(curlevel,1,"", decode(curlevel, 2, "점소계", lobranNm ))} suppress=1 </c> '
        // gr_retrieve_target += '<c> id="dptWrkPlNm"          name="출발역"               width=80 align=center value={decode(curlevel,1,"구간계", decode(curlevel,2,"", dptWrkPlNm ))} </c>            '
        // gr_retrieve_target += '<c> id="arvWrkPlNm"          name="도착역"               width=80 align=center value={decode(curlevel,1,"", decode(curlevel,2,"", arvWrkPlNm ))} </c>    
        gr_retrieve_target += '            <w2:column displayMode="label" id="header0" sortable="true" inputType="text" value="" width="100" hidden="true"></w2:column>'
        gr_retrieve_target += '            <w2:column displayMode="label" id="header1" sortable="true" inputType="text" style="" value="배차점소" width="100"></w2:column>'
