scwin.dtlCustomFormatter = function(data, formatData, rowIndex, columnIndex){
    var columnId = ds_retrieveDtl.getColumnID(columnIndex);
    var returnData = data;
    if (columnId == "cntrSizCd"){
        returnData = data + ds_retrieveDtl.getCellData(rowIndex, "cntrTypCd");
    }
    return returnData;
}

